    char** groups = malloc(capacity * sizeof(char*));
    char* buffer = malloc(length + 1);
    int buffer_index = 0;
    *group_count = 0;

    for (int i = 0; i < length; ++i) {
        char chr = paren_string[i];
        if (chr == '(') {
            level++;
            buffer[buffer_index++] = chr;
