                (*group_count)++;
                if (*group_count >= capacity) {
                    capacity *= 2;
                    groups = realloc(groups, capacity * sizeof(char*));
                }
                buffer_index = 0;
            }
        }
    }

    free(buffer);
    return groups;
}

